# ── Run seeding ───────────────────────────────────────────────────────────────

def seed(force_update=False):
    """
    force_update=True  → overwrite every existing entry with the latest answer/comments.
    force_update=False → skip entries that already exist (safe default).
    """
    import json

    with app.app_context():
        # app_context() is required for any database operation outside of a Flask request
        added, updated, skipped = 0, 0, 0  # track exactly what happened

        for entry in ENTRIES:  # loop through every QB entry defined above
            existing = QuestionBankEntry.query.filter_by(key=entry["key"]).first()

            if existing:
                if force_update:
                    # overwrite the stored answer, severity, and tags with the new values
                    existing.answer   = entry["answer"]
                    existing.severity = entry.get("severity", "info")
                    existing.tags     = json.dumps(entry.get("tags", []))
                    updated += 1
                else:
                    skipped += 1  # already exists and not forcing an update — leave it alone
                continue

            # entry doesn't exist yet — insert it fresh
            db.session.add(QuestionBankEntry(
                key      = entry["key"],                       # topic phrase used for matching
                answer   = entry["answer"],                    # full Markdown response text
                severity = entry.get("severity", "info"),      # default to "info" if not set
                tags     = json.dumps(entry.get("tags", []))   # convert list → JSON string for SQLite storage
            ))
            added += 1

        db.session.commit()  # write all staged inserts and updates to the DB in one transaction
        total = QuestionBankEntry.query.count()  # live count of all rows now in the table
        print(f"✓ Done — added: {added}, updated: {updated}, skipped: {skipped}, total in DB: {total}")


if __name__ == "__main__":
    import sys
    # pass --update on the command line to overwrite existing entries with the latest answers
    # example: python seed_qb.py --update
    force = '--update' in sys.argv
    if force:
        print("Running in UPDATE mode — all existing entries will be overwritten with new answers.")
    seed(force_update=force)
